const VOB_CLICK_PATTERN_STRINGS_PRIMARY = [
  '\\bverify\\s+(?:benefits|eligibility)\\b',
  '\\bbenefits?\\s+verification\\b',
  '\\beligibility\\s*(?:check|verification|inquiry)?\\b',
  '\\bcheck\\s+(?:coverage|eligibility)\\b',
