/** Normalize member ID tokens after OCR (OI→01, trim junk after first id chunk). */
function normalizeMemberIdChunk(raw = '') {
  let t = cleanExtractedValue(String(raw || ''));
  t = t.replace(/\bOI\b/gi, '01');
  t = t.replace(/\b0l\b/gi, '01');
  const parts = t.split(/\s+/).filter(Boolean);
  if (!parts.length) return '';
  const head = parts[0].replace(/[lI]/g, '1').replace(/O/g, '0');
  if (/^[A-Z]?\d{6,14}$/i.test(head)) {
    if (parts[1] && /^(01|0[1l]|OI|1)$/i.test(parts[1])) {
      return `${head} 01`.replace(/\s+/g, ' ').trim();
    }
    if (parts.length === 1) return head;
    if (/^\d{1,2}$/.test(parts[1])) {
      return `${head} ${parts[1]}`.replace(/\s+/g, ' ').trim();
    }
    return head;
  }
  return t;
}

